fn main() {
    // DAG: nodes 1-8, edges: (1,3),(1,4),(2,4),(2,5),(3,6),(4,6),(4,7),(5,7),(6,8),(7,8)
    let n = 8;
    let edges = [(1,3),(1,4),(2,4),(2,5),(3,6),(4,6),(4,7),(5,7),(6,8),(7,8)];

    // Build predecessors for each node
    let mut pred: Vec<Vec<u32>> = vec![vec![]; n + 1];
    for &(u, v) in &edges {
        pred[v as usize].push(u);
    }

    // Memoization map: mask -> count
    let mut memo: std::collections::HashMap<u32, u64> = std::collections::HashMap::new();

    fn count_topo(mask: u32, n: usize, pred: &Vec<Vec<u32>>, memo: &mut std::collections::HashMap<u32, u64>) -> u64 {
        let full_mask = (1 << n) - 1;
        if mask == full_mask {
            return 1;
        }
        if let Some(&cached) = memo.get(&mask) {
            return cached;
        }

        let mut total: u64 = 0;
        for node in 1..=n {
            let bit = 1 << (node - 1);
            if mask & bit != 0 {
                continue;
            }
            // Check if all predecessors are placed
            let preds_placed = pred[node].iter().all(|&p| (mask >> (p - 1)) & 1 == 1);
            if preds_placed {
                total += count_topo(mask | bit, n, pred, memo);
            }
        }

        memo.insert(mask, total);
        total
    }

    let result = count_topo(0, n, &pred, &mut memo);
    println!("{}", result);
}
